    rows, transformation_functions, overwrite_columns, old_column_names
):
    """
    Read rows from csv, apply transformation to columns using
    transformation_functions, and yield processed rows
    """
    for i, row in enumerate(rows, 1):
        for column in row:
            if column is None:
                continue
            try:
                default_value = transformation_functions[type(column)](column)
            except KeyError:
                raise Exception(
                    f"Could not read column of type {type(column)} "
                    "as transformation function. Cannot replace with default value."
                )
            if column is None:
                column = default_value
            if overwrite_columns and old_column_names and column in old_column_names:
                old_ix = old_column_names.index(column)
                column = default_value
                column[i] = old_ix
            row[i] = column
